const input = $('When Called').first().json;
const fileContent = $input.first().json.data || $input.first().json.body || '';
const fileType = input.file_type?.toLowerCase() || '';
const fileName = input.file_name || 'uploaded_file';

let textContent = '';

// Handle different file types
if (fileType === 'txt' || fileType === 'md' || fileType === 'text/plain' || fileType === 'text/markdown') {
  textContent = typeof fileContent === 'string' ? fileContent : JSON.stringify(fileContent);
} else if (fileType === 'json' || fileType === 'application/json') {
  try {
    const parsed = typeof fileContent === 'string' ? JSON.parse(fileContent) : fileContent;
    textContent = JSON.stringify(parsed, null, 2);
  } catch (e) {
    textContent = String(fileContent);
  }
} else if (fileType === 'pdf' || fileType === 'application/pdf') {
  // PDF extraction would need a separate service
  // For now, mark as needing processing
  textContent = `[PDF File: ${fileName} - Content extraction pending]`;
} else {
  textContent = String(fileContent);
}

// Prepare for embedding
const documentText = `File: ${fileName}\nType: ${fileType}\n\n${textContent}`;

return {
  json: {
    userID: input.userID,
    category: input.category || 'documents',
    file_name: fileName,
    file_type: fileType,
    content: documentText
  }
};

const processed = $('Process File').first().json;

return {
  json: {
    success: true,
    action: 'file_uploaded',
    user_id: processed.userID,
    file_name: processed.file_name,
    file_type: processed.file_type,
    category: processed.category,
    timestamp: new Date().toISOString()
  }
};
